<template>
  <div class="saved-workouts">
    <button class="showButton" @click="showWorkouts">
      {{ !show ? "Show Workouts" : "Hide Workouts" }}
    </button>
    <div v-if="show">
      <div class="workouts">
        <div class="show-workouts" v-for="w in workouts" :key="w.id">
          <p>
            Date: {{ w.date }} | Name: {{ w.workoutName }} | Reps:
            {{ w.workoutReps }} | Sets: {{ w.workoutSets }}
            <button @click="deleteWorkout(w.id)">X</button>
          </p>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { projectFirestore } from "@/firebase/config";
import { ref, watchEffect } from "vue";

export default {
  setup() {
    const workoutsData = ref([]);
    const workouts = ref([]);
    const show = ref(false);

    const showWorkouts = () => {
      show.value = !show.value;

      const docRef = projectFirestore.collection("workouts");
      const unsub = docRef.onSnapshot((snap) => {
        const result = [];
        snap.docs.forEach((doc) => {
          result.push({ ...doc.data() });
        });
        workouts.value = result;
        return workouts;
      });
      watchEffect((onInvalidate) => {
        onInvalidate(() => unsub());
      });
    };

    const deleteWorkout = (id) => {
      projectFirestore.collection("workouts").doc(id).delete();
    };
    return { deleteWorkout, workoutsData, showWorkouts, show, workouts };
  },
  mounted() {},
};
</script>

<style scoped>
.saved-workouts {
  margin-top: 30px;
}
.saved-workouts button {
  background-color: black;
  border-radius: 5px;
  color: beige;
  cursor: pointer;
}
.show-workouts {
  display: flex;
  justify-content: space-around;
  align-items: center;
  width: 400px;
  margin: 0 auto;
  font-size: 14px;
  margin-top: 15px;
}
.show-workouts p {
  display: flex;
  justify-content: space-between;
  align-items: center;
  width: 100%;
  margin-top: -10px;
  padding: 5px;
  background-color: beige;
}
.show-workouts button {
  display: flex;
  justify-content: right;
  align-items: center;
  background-color: black;
  border-radius: 5px;
  color: beige;
  cursor: pointer;
}
</style>
