<template>
  <h3 class="title">Add Workout</h3>
  <div class="date-picker">
    <Datepicker v-model="date"></Datepicker>
  </div>
  <form
    class="form-container"
    @submit.prevent="createWorkout(date, workoutName, workoutReps, workoutSets)"
  >
    <input
      class="form-input"
      type="text"
      placeholder="Workout name.."
      required
      v-model="workoutName"
    />
    <input
      class="form-input"
      type="text"
      placeholder="Workout reps.."
      required
      v-model="workoutReps"
    />
    <input
      class="form-input"
      type="text"
      placeholder="Workout sets.."
      required
      v-model="workoutSets"
    />
    <button>Add</button>
  </form>
  <div>
    <SavedWorkouts />
  </div>
</template>

<script>
import SavedWorkouts from "./SavedWorkouts.vue";
import Datepicker from "@vuepic/vue-datepicker";
import "@vuepic/vue-datepicker/dist/main.css";
import { projectFirestore } from "@/firebase/config";
import { ref } from "@vue/reactivity";
import moment from "moment";

export default {
  components: { SavedWorkouts, Datepicker },
  setup() {
    const date = ref();

    const workoutName = ref("");
    const workoutReps = ref("");
    const workoutSets = ref("");
    const workouts = ref([]);

    const createWorkout = (date, name, reps, sets) => {
      const formattedDate = moment(date).format("YYYY-MM-D");
      let docId = Math.floor(Math.random() * 10000).toString();
      projectFirestore
        .collection("workouts")
        .doc(docId)
        .set({
          id: docId,
          date: formattedDate,
          workoutName: name,
          workoutReps: reps,
          workoutSets: sets,
        })
        .then(() => {
          console.log("Sucess");
          date.value = "";
          workoutName.value = "";
          workoutReps.value = "";
          workoutSets.value = "";
        })
        .catch((error) => {
          console.log("Error", error);
        });
    };
    return {
      createWorkout,
      date,
      workoutName,
      workoutReps,
      workoutSets,
      workouts,
    };
  },
};
</script>

<style scoped>
.title {
  margin-top: 30px;
  font-size: 24px;
}
.date-picker {
  display: flex;
  justify-content: center;
}
.form-container {
  margin: 10px auto;
  max-width: 200px;
  margin-top: -10px;
}
.form-container button {
  width: 70px;
  height: 35px;
  background-color: beige;
  border-radius: 10px;
  border: none;
  cursor: pointer;
  margin-top: 25px;
}
.form-input {
  width: 150px;
  height: 30px;
  font-size: 18px;
  text-align: center;
  margin-top: 25px;
  border: none;
  border-bottom: 1px solid black;
}
</style>
